using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpServer;

[McpServerToolType]
public sealed class ApiTools
{
    private readonly IHttpClientFactory _httpClientFactory;

    public ApiTools(IHttpClientFactory httpClientFactory)
    {
        _httpClientFactory = httpClientFactory;
    }

    [McpServerTool(Name = "fetch_api"), Description("Fetches JSON data from an external API endpoint.")]
    public async Task<string> FetchApiAsync(
        [Description("The full URL of the API endpoint to call.")] string url,
        CancellationToken cancellationToken)
    {
        using var client = _httpClientFactory.CreateClient("ApiClient");
        using var response = await client.GetAsync(url, cancellationToken);

        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
        return JsonSerializer.Serialize(json, new JsonSerializerOptions { WriteIndented = true });
    }
}

using System.ComponentModel;
using ModelContextProtocol.Protocol;
using ModelContextProtocol.Server;

namespace McpServer;

[McpServerPromptType]
public sealed class SummarizationPrompts
{
    [McpServerPrompt(Name = "summarize"), Description("Generates a prompt that asks the model to summarize the provided text.")]
    public static IEnumerable<PromptMessage> Summarize(
        [Description("The text content to summarize.")] string text,
        [Description("Optional desired length: 'short', 'medium', or 'long'.")] string? length = "medium")
    {
        yield return new PromptMessage
        {
            Role = Role.User,
            Content = new TextContentBlock
            {
                Text = $"""
                    Please summarize the following text. Target a {length} summary length.

                    Text to summarize:
                    ---
                    {text}
                    ---
                    """
            }
        };
    }
}

